function checkAnswer(answer, correctAnswer, ctx) {
 //替换json标记
 const result = answer.replace(/```json|```/g, '');
 //图像
 const image = "/dataset-file/测试集v1/assets/imgbox1.jpg"
 //传入网页
 const getVisualizerHtml = () => `
<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"> <style>
body{ margin:0; padding:20px; display:flex; justify-content:center; align-items:flex-start;}
.container {position:relative;display:inline-block;line-height:0;box-shadow: 2px 2px 13px 5px rgb(0,0,0,0.4);}
img {display:block;max-width:100vw;max-height:calc(100vh - 40px);object-fit:contain;}
.box{position:absolute; border:2px solid; pointer-events:none; box-sizing:border-box;}
.label{position:absolute; top:-2px;color:white; font-size:12px; padding:10px;font-weight:bold;z-index:10;}
</style></head><body>
<div class="container" id="c"><img src="${image}" id="i"></div>
<script>(function(){
const data = ${result};
const container = document.getElementById('c');
const getColor = (idx) => \`hsl(\${idx * 137.5 % 360}, 80%, 50%)\`;
data.forEach((item, idx) => {
const color = getColor(idx);
for (let name in item) {
const [x1, y1, x2, y2] = item[name];
if (!x1 && x1 !== 0) continue; //简单校验数据有效性
const box = document.createElement('div');
box.className = 'box';
Object.assign(box.style, {
left:(x1 * 100) + '%',
top:(y1 * 100) + '%',
width:((x2 - x1) * 100) + '%',
height:((y2 - y1) * 100) + '%',
borderColor:color});
const lbl = document.createElement('div');
lbl.className = 'label';
lbl.innerText = name;
lbl.style.backgroundColor = color;
box.appendChild(lbl);
container.appendChild(box);
}});})();</script></body></html>`;

 const encodedHtml = btoa(encodeURIComponent(getVisualizerHtml()));
 return {
 percent: (answer.trim() === correctAnswer.trim()) ? 1 : 0.5,
 html: `<div><button type="button"
 onclick="const w=window.open(); w.document.write(decodeURIComponent(atob('${encodedHtml}'))); w.document.close();">
 查看可视化结果
 </button>
 </div>`
 };
}

